[{title Summer of Blood} {released 1397692800000} {score 0.9934720396995544}]
[{title Summer Games} {released 1328659200000} {score 0.15982933342456818}]
[{title Summer of Goliath} {released 1310083200000} {score 0.13038821518421173}]
```**Java-sync:**Java (Sync)* Create a new file named `SortByDate.java`
  and paste the following code:

  ```java
  import java.util.Arrays;
  import java.util.List;

  import static com.mongodb.client.model.Aggregates.limit;
  import static com.mongodb.client.model.Aggregates.project;
  import static com.mongodb.client.model.Projections.*;
  import com.mongodb.client.MongoClient;
  import com.mongodb.client.MongoClients;
  import com.mongodb.client.MongoCollection;
  import com.mongodb.client.MongoDatabase;
  import org.bson.Document;

  import java.time.Instant;
  import java.util.Date;

  public class SortByDate {
    public static void main( String[] args ) {
      // define query
  	    Document agg =
  	        new Document("$search", 
  	        	    new Document("index", "default")
  	                .append("compound", 
  	        new Document("filter", Arrays.asList(new Document("wildcard", 
  	                        new Document("query", "Summer*")
  	                                .append("path", "title"))))
  	                    .append("must", Arrays.asList(new Document("near", 
  	                        new Document("pivot", 13149000000L)
  	                                .append("path", "released")
  	                                .append("origin", Date.from(Instant.parse("2014-04-18T00:00:00.000+00:00")))))))
  	                .append("sort", new Document("released", -1)));

      // specify connection
      String uri = "<connection-string>";

      // establish connection and set namespace
      try (MongoClient mongoClient = MongoClients.create(uri)) {
        MongoDatabase database = mongoClient.getDatabase("sample_mflix");
        MongoCollection<Document> collection = database.getCollection("movies");
  	  // run query and print results
        collection.aggregate(Arrays.asList(agg, 
          limit(5), 
          project(fields(exclude("_id"), include("title"), include("released"), computed("score", new Document("$meta", "searchScore"))))))
          .forEach(doc -> System.out.println(doc.toJson()));	
      }
    }
  }

  ```

  > **Note:** To run the sample code in your Maven environment, add the
  > following code above the import statements in your file.
  >
  > ```
  > package com.mongodb.drivers;
  > ```

